function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const prets = data.prets;

  const sujet = (T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE)
              + ` - ${stats.total_prets} dossier(s)`;

  // ── Corps email ──
  let body = `${T.salutation} ${dest.prenom} ${dest.nom},\n\n`;
  body += `${T.introduction[data.type_destinataire]}\n\n`;
  body += `══════════════════════════════════════════════════════════\n`;
  body += `📊 ${T.section_stats}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${getEmoji(stats.jours_min)} Niveau d'escalade : ${data.niveau_escalade}\n`;
  body += `${T.total} : ${stats.total_prets}\n`;
  body += `${T.montant_total} : ${formaterMontant(stats.montant_total, T.devise)}\n`;
  body += `${T.montant_accorde} : ${formaterMontant(stats.montant_accorde_total, T.devise)}\n`;
  body += `${T.delai_min} : ${stats.jours_min} ${T.jours}\n`;
  body += `${T.delai_total} : ${stats.delai_total} ${T.jours}\n`;
  if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `${T.seuil_dga} : ${stats.seuil_dga} ${T.jours}\n`;
  }

  body += `\n══════════════════════════════════════════════════════════\n`;
  body += `💰 ${T.section_prets}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;

  prets.forEach((pret, i) => {
    body += `${i + 1}. ${getEmoji(pret.jours_restants)} ${pret.num_pret}\n`;
    body += `   📅 ${T.date_pret} : ${formaterDate(pret.date_pret, langue)}\n`;
    body += `   🗂️  ${T.date_creation} : ${formaterDateHeure(pret.date_creation, langue)}\n`;
    body += `   👤 ${T.salarie_concerne} : ${pret.salarie_concerne.prenom} ${pret.salarie_concerne.nom}`;
    if (pret.salarie_concerne.matricule) body += ` (${T.matricule}: ${pret.salarie_concerne.matricule})`;
    body += `\n`;
    if (pret.montant_pret) body += `   💵 ${T.montant_pret} : ${formaterMontant(pret.montant_pret, T.devise)}\n`;
    if (pret.montant_accorde) body += `   ✅ ${T.montant_accorde_label} : ${formaterMontant(pret.montant_accorde, T.devise)}\n`;
    if (pret.motif_pret) body += `   📝 ${T.motif} : ${pret.motif_pret}\n`;
    body += `   ⏰ ${T.delai_label} : ${pret.jours_restants} ${T.jours} ${T.restant} (${T.limite} : ${formaterDate(pret.date_limite, langue)})\n`;
    if (pret.jours_restants <= 2) body += `   🚨 ${T.urgent}\n`;
    body += `\n`;
  });

  body += `══════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    body += `🚨 ${T.action_requise} : ${T.urgent}\n`;
  } else if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `📌 ${T.instruction_dga}\n`;
  } else {
    body += `📌 ${T.instruction}\n`;
  }
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (data.type_destinataire === 'PDG') body += `🔴 Notification URGENTE envoyée au PDG\n`;
  if (data.type_destinataire === 'DGA') body += `🟠 Notification DGA (seuil mi-délai: ${stats.seuil_dga}j)\n`;
  body += `${T.ne_pas_repondre}\n`;

  // ── Telegram ──
  let tg = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  tg += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  tg += `👤 *${dest.prenom} ${dest.nom}*\n\n`;
  tg += `📊 *${T.section_stats}*\n`;
  tg += `${T.total} : *${stats.total_prets}*\n`;
  tg += `💰 ${T.montant_total} : *${formaterMontant(stats.montant_total, T.devise)}*\n`;
  tg += `${T.delai_min} : *${stats.jours_min} ${T.jours}*\n\n`;
  tg += `💰 *${T.section_prets}*\n\n`;

  prets.slice(0, 5).forEach((pret, i) => {
    tg += `${i + 1}. ${getEmoji(pret.jours_restants)} *${pret.num_pret}*\n`;
    tg += `   👤 ${pret.salarie_concerne.prenom} ${pret.salarie_concerne.nom}\n`;
    if (pret.montant_pret) tg += `   💵 ${formaterMontant(pret.montant_pret, T.devise)}\n`;
    tg += `   ⏰ ${pret.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });

  if (prets.length > 5) tg += `... et ${prets.length - 5} autre(s) dossier(s)\n\n`;
  if (stats.jours_min <= 2) tg += `🚨 *${T.urgent}*\n`;

  return {
    email:    { subject: sujet, body },
    telegram: { text: tg, parse_mode: 'Markdown' }
  };
}

// ─────────────────────────────────────────────────────────────
// MESSAGE CC
// ─────────────────────────────────────────────────────────────
function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const stats = data.statistiques;
  const prets = data.prets;
  const destPrincipal = data.destinataire_principal;

  const labels = { PDG: 'le PDG', DGA: 'le DGA', SUPERIEUR: 'votre supérieur(e)', FARHAT: 'le Responsable RH', BAALLAH: 'la Direction' };
  const label = labels[typeDestinatairePrincipal] || typeDestinatairePrincipal;

  const sujet = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_prets} dossier(s)`;

  let body = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  body += `Un message d'alerte concernant les dossiers de prêts non attachés a été envoyé à ${label} ${destPrincipal.prenom} ${destPrincipal.nom}.\n\n`;
  body += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade} | ${T.total}: ${stats.total_prets} | ${T.montant_total}: ${formaterMontant(stats.montant_total, T.devise)} | ${T.delai_min}: ${stats.jours_min} ${T.jours}\n\n`;
  body += `══════════════════════════════════════════════════════════\n`;
  body += `💰 ${T.section_prets}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;

  prets.forEach((pret, i) => {
    body += `${i + 1}. ${getEmoji(pret.jours_restants)} ${pret.num_pret}\n`;
    body += `   👤 ${pret.salarie_concerne.prenom} ${pret.salarie_concerne.nom}\n`;
    if (pret.montant_pret) body += `   💵 ${T.montant_pret}: ${formaterMontant(pret.montant_pret, T.devise)}\n`;
    body += `   ⏰ ${pret.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(pret.date_limite, langue)})\n\n`;
  });

  body += `Veuillez prendre les mesures nécessaires pour traiter ces dossiers dans les délais impartis.\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} | ${T.copie_info} | ${T.ne_pas_repondre}\n`;

  let tg = `${T.copie_info}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  tg += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  tg += `Un message a été envoyé à *${destPrincipal.prenom} ${destPrincipal.nom}* (${label}).\n\n`;
  tg += `📊 ${T.total}: *${stats.total_prets}* | 💰 *${formaterMontant(stats.montant_total, T.devise)}* | ⏰ *${stats.jours_min} ${T.jours}*\n\n`;

  prets.slice(0, 3).forEach((pret, i) => {
    tg += `${i + 1}. ${getEmoji(pret.jours_restants)} *${pret.num_pret}*\n`;
    tg += `   👤 ${pret.salarie_concerne.prenom} ${pret.salarie_concerne.nom}\n`;
    if (pret.montant_pret) tg += `   💵 ${formaterMontant(pret.montant_pret, T.devise)}\n`;
    tg += `   ⏰ ${pret.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });
  if (prets.length > 3) tg += `... et ${prets.length - 3} autre(s)\n\n`;

  return {
    email:    { subject: sujet, body },
    telegram: { text: tg, parse_mode: 'Markdown' }
  };
}

// ─────────────────────────────────────────────────────────────
// DISPATCH
// ─────────────────────────────────────────────────────────────
const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messages = genererMessagePrincipal(data);

  // Message principal
  results.push({
    json: {
      ...data,
      messages,
      type_envoi:         'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }
  });

  // CC SUPERIEUR → copie au créateur
  if (data.type_destinataire === 'SUPERIEUR' && data.createur?.chat_id) {
    const messagesCC = genererMessageCC(data, data.createur, 'SUPERIEUR');
    results.push({ json: {
      ...data, messages: messagesCC, type_envoi: 'CC',
      destinataire_final: data.createur, cc_pour_profil: 'CREATEUR',
      meta: { ...data.meta, langue_message: data.createur.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }

  // CC PDG → copie supérieur + créateur
  if (data.type_destinataire === 'PDG') {
    if (data.superieur?.chat_id) {
      const msgCCSup = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSup, type_envoi: 'CC',
        destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR',
        meta: { ...data.meta, langue_message: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
    if (data.createur?.chat_id) {
      const msgCCSal = genererMessageCC(data, data.createur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSal, type_envoi: 'CC',
        destinataire_final: data.createur, cc_pour_profil: 'CREATEUR',
        meta: { ...data.meta, langue_message: data.createur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
  }
});

console.log(`\n📧 Messages générés: ${results.length}`);
console.log(`  - Principaux: ${results.filter(r => r.json.type_envoi === 'PRINCIPAL').length}`);
console.log(`  - CC:         ${results.filter(r => r.json.type_envoi === 'CC').length}`);
console.log('═══════════════════════════════════════════════════\n');

return results;
